use audesys_hal_core::types::{HalError, HalPinType};
use audesys_hal_core::{HalValue, decode_halvalue, encode_halvalue};

// ── Float comparison helpers ──

/// Roundtrip f32 values and compare via to_bits() (NaN-safe).
fn rt_f32(v: HalValue) {
    let encoded = encode_halvalue(&v);
    let decoded = decode_halvalue(&encoded).expect("decode f32 failed");
    match (&v, &decoded) {
        (HalValue::F32(a), HalValue::F32(b)) => {
            assert_eq!(a.to_bits(), b.to_bits(), "f32 roundtrip bit mismatch");
        }
        _ => panic!("expected F32 roundtrip, got {:?} → {:?}", v, decoded),
    }
}

/// Roundtrip f64 values and compare via to_bits() (NaN-safe).
fn rt_f64(v: HalValue) {
    let encoded = encode_halvalue(&v);
    let decoded = decode_halvalue(&encoded).expect("decode f64 failed");
    match (&v, &decoded) {
        (HalValue::F64(a), HalValue::F64(b)) => {
            assert_eq!(a.to_bits(), b.to_bits(), "f64 roundtrip bit mismatch");
        }
        _ => panic!("expected F64 roundtrip, got {:?} → {:?}", v, decoded),
    }
}

/// Roundtrip a non-float HalValue via PartialEq.
fn rt(v: HalValue) {
    let encoded = encode_halvalue(&v);
    let decoded = decode_halvalue(&encoded).expect("decode failed");
    assert_eq!(v, decoded, "roundtrip mismatch for {:?}", v);
}

