#[test]
fn test_type_30_pin_type_identity() {
    // S-TYPE-030: For each variant, pin_type() returns correct HalPinType
    assert_eq!(HalValue::Bool(true).pin_type(), HalPinType::Bool);
    assert_eq!(HalValue::Bool(false).pin_type(), HalPinType::Bool);
    assert_eq!(HalValue::S8(0).pin_type(), HalPinType::S8);
    assert_eq!(HalValue::U8(0).pin_type(), HalPinType::U8);
    assert_eq!(HalValue::S16(0).pin_type(), HalPinType::S16);
    assert_eq!(HalValue::U16(0).pin_type(), HalPinType::U16);
    assert_eq!(HalValue::S32(0).pin_type(), HalPinType::S32);
    assert_eq!(HalValue::U32(0).pin_type(), HalPinType::U32);
    assert_eq!(HalValue::S64(0).pin_type(), HalPinType::S64);
    assert_eq!(HalValue::U64(0).pin_type(), HalPinType::U64);
    assert_eq!(HalValue::F32(0.0).pin_type(), HalPinType::F32);
    assert_eq!(HalValue::F64(0.0).pin_type(), HalPinType::F64);
    assert_eq!(HalValue::Blob(vec![]).pin_type(), HalPinType::Blob);
    assert_eq!(HalValue::String("".into()).pin_type(), HalPinType::String);
    assert_eq!(
        HalValue::Array { element_type: HalPinType::S32, data: vec![] }.pin_type(),
        HalPinType::S32
    );
}

